const token = $input.first().json.propertyName;
const base = 'https://mk.conectivainfor.com.br/mk';
const body = $('Webhook Trigger').first().json.body || {};

async function mkGet(endpoint, extra) {
  try {
    const url = base + '/' + endpoint + '.rule?sys=MK0&token=' + token + (extra || '');
    const data = await this.helpers.httpRequest({ method: 'GET', url, json: true, timeout: 15000 });
    return data;
  } catch(e) {
    return { _error: e.message };
  }
}

const fn = mkGet.bind(this);

const [planos, regrasVcto, sla, regraBloq, profilePgto, planoContas, descontos, tiposOS] = await Promise.all([
  fn('WSMKListaPlanoAcesso', '&TipoPlano=1'),
  fn('WSMKListaRegraVencimento'),
  fn('WSMKListaTabelaSLA'),
  fn('WSMKListaRegraBloqueio'),
  fn('WSMKListaProfilePagamento', '&CodigoFormaPagamento=3'),
  fn('WSMKPlanoContas'),
  fn('WSMKListaDesconto'),
  fn('WSMKOSListaTiposOS'),
]);

return [{
  json: {
    success: true,
    data: {
      planos: (planos.Planos || []).filter(p => p.inativo === 'N'),
      regrasVencimento: regrasVcto.RegrasVencimento || [],
      tabelasSLA: sla.TabelaSLA || [],
      regrasBloqueio: regraBloq.RegraBloqueio || [],
      profilesPagamento: profilePgto.ProfilesPagamento || [],
      planoContas: planoContas.PlanoContas || [],
      descontos: descontos.RegrasDesconto || [],
      tiposOS: tiposOS.Tipos || [],
    },
    endpoint: 'WSMKListaParamsContrato',
    session_id: body.session_id || null,
  }
}];
